  389,
  false, false, false,
  ARRAY['Structured differential diagnosis with ranked reasoning', 'Accessible without EHR integration  -  runs in browser and mobile', 'Useful for both clinical practice and medical education', 'AI explains reasoning behind each differential entry', 'Free tier available for individual use'],
  ARRAY['Not a documentation tool  -  separate from note generation', 'AI reasoning requires physician validation for clinical decisions', 'Limited integration with EHR workflows'],
  ARRAY['Differential diagnosis generation for complex patient presentations', 'Clinical assessment and plan drafting from case summaries', 'Medical education and resident training support']
),

(
  'nuance-dax',
  'Nuance DAX',
  'Microsoft AI ambient clinical intelligence for enterprise health',
  E'Nuance DAX (Dragon Ambient eXperience) is Microsoft''s enterprise AI clinical documentation platform, built on the Dragon medical transcription foundation that has been the standard for physician dictation for over two decades. DAX represents the evolution from structured dictation into fully ambient AI documentation: the system listens to the entire patient encounter and automatically generates a complete, speciality-specific clinical note without physician input during the visit.\n\nDAX is deeply integrated with Epic, Cerner, and Oracle Health EHR systems at the enterprise level. Microsoft''s Azure infrastructure provides the processing scale for health system-wide deployment. The platform supports over 50 specialties with specialty-specific note templates and has been deployed at major health systems across the United States including Duke Health, Providence, and Sutter Health.\n\nFor health systems already running Microsoft Azure or Nuance Dragon, DAX is the natural enterprise progression. The combination of Microsoft''s healthcare data agreements, Epic marketplace integration, and the Dragon brand reputation in clinical settings gives DAX the strongest existing-relationship procurement path of any ambient documentation platform. The pricing reflects enterprise deployment: custom contracts rather than per-seat rates.',
  'https://www.google.com/s2/favicons?domain=nuance.com&sz=64',
  'https://nuance.com',
  'https://nuance.com',
  ARRAY['healthcare'],
  'paid',
  false,
  0.00,
  4.7,
  567,
  false, false, false,
  ARRAY['Enterprise-grade with Microsoft Azure infrastructure', 'Deep Epic, Cerner, and Oracle Health EHR integration', 'Deployed at major US health systems with proven scale', 'Built on Dragon dictation platform trusted for 20+ years', 'Supports 50+ medical specialties with tailored note templates'],
  ARRAY['Enterprise-only procurement  -  not available for individual physicians', 'Custom pricing without transparency  -  lengthy sales process', 'Microsoft ecosystem dependency for optimal deployment'],
